#!/usr/bin/env bash
# product-tabletop.sh — 产品/电商台面 (Product / Tabletop) SOP walkthrough for 摄影.
# Auto-generated by cli_writer.py. Source: research/03-workflows.md.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="摄影"
WORKFLOW="产品/电商台面 (Product / Tabletop)"

usage() {
  cat <<EOF
product-tabletop.sh — Walk through "${WORKFLOW}" SOP for ${INDUSTRY}

逐步走完这个工作流的入门 SOP, 然后做失败模式自检, 输出走查报告。

USAGE:
  ./product-tabletop.sh             # interactive
  ./product-tabletop.sh --dry-run
  ./product-tabletop.sh --json
  ./product-tabletop.sh --explain
  ./product-tabletop.sh --help
EOF
}

explain() {
  cat <<'EOT'
这个 SOP 走查脚本帮你完成 "产品/电商台面 (Product / Tabletop)" 工作流。

一句话: 在台面上从控反光的布光、稳固支撑/构图、到景深合成、再到后期修瑕，产出清晰、无杂反光、全景深的商业产品图。

入门 SOP 共 4 步, 失败模式自检 3 项。

相关心智模型:
  • 先问光，再问相机（光是主语，器材是宾语）: 摄影的第一性是「看光、控光、塑光」——画面好坏由光的方向/质感/光比决定，相机机身只是记录介质；资深人拿到任何场景先读光，外行先问「该买哪台相机」。
  • 成像前就决定成像（previsualization / 决定性瞬间）: 好照片在按快门之前就已在脑中成形——Adams 的「预想」(previsualization) 与 Cartier-Bresson 的「决定性瞬间」是同一直觉的两极：前者构建式预想最终影调，后者抓取式

来源: research/03-workflows.md.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a SOP_STEPS=(
  "**布光控反光**: 用 softbox/柔光 + 旗板/黑卡控制反光物体（电子/玻璃/金属）的高光与色彩溢出，单灯起步先控住一个主反光面。跳过 → 反光面一片死白或映出环境杂物/摄影师。(evidence: [T03-S019, T03-S020])"
  "**支撑 + 构图**: 三脚架固定机位（台面必须稳）、用支架/粘土/吊线固定产品角度，安排构图与背景。跳过脚架 → 长曝/景深合成糊掉、机位不可复现。(evidence: [T02-S010])"
  "**对焦 + 拍摄**: 用微距镜（90/100/105）对产品关键面合焦拍摄。跳过 → 细节不锐、放大露怯。(evidence: [T02-S032])"
  "**后期修瑕**: 进 PS/C1 清灰尘/划痕、修反光、抠背景、统一影调。跳过 → 灰尘瑕疵在白底上全暴露，不可上架。(evidence: [T02-S015])"
)
declare -a FAILURE_MODES=(
  "**反光物体加更多灯**: 反光面映出更多杂物更乱 → 减灯 + 用黑卡 negative fill 控高光，单灯精确雕。**CLI 自检**: 「反光问题你是靠加灯还是靠黑/白卡控？反光物体往往要减光。」"
  "**小光圈硬凑景深**: f/22 衍射使整体变软 → 用镜头最佳光圈 + focus stacking 堆栈兼顾景深与锐度。**CLI 自检**: 「需要前后全清晰时，你是 f/22 硬凑，还是堆栈？」"
  "**不修瑕直接上架**: 白底灰尘/划痕全暴露 → 后期逐个清灰修反光。"
)
declare -a STEP_STATUS=()
declare -a STEP_NOTES=()
declare -a FAIL_CHECK=()

ms_section "${INDUSTRY} · ${WORKFLOW} 走查"
ms_info "逐步走完 ${#SOP_STEPS[@]} 步入门 SOP。每步可标 done / skipped / blocked。"
echo

for i in "${!SOP_STEPS[@]}"; do
  ms_section "Step $((i+1))/${#SOP_STEPS[@]}: ${SOP_STEPS[$i]}"
  ms_prompt "状态? [d=done / s=skipped / b=blocked]"
  read -r status
  STEP_STATUS+=("${status:-d}")
  case "${status:-d}" in
    s) ms_prompt "跳过原因 (一句话):"; read -r note ;;
    b) ms_prompt "blocker (一句话):"; read -r note ;;
    *) note="" ;;
  esac
  STEP_NOTES+=("$note")
done

if [[ ${#FAILURE_MODES[@]} -gt 0 ]]; then
  ms_section "失败模式自检"
  for fm in "${FAILURE_MODES[@]}"; do
    if ms_confirm "你是否避免了 — '$fm' ?"; then
      FAIL_CHECK+=("✓ $fm")
    else
      FAIL_CHECK+=("✗ $fm")
    fi
  done
fi

ms_buffer_append "# ${INDUSTRY} — ${WORKFLOW} 走查报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## SOP 步骤"
ms_buffer_append ""
for i in "${!SOP_STEPS[@]}"; do
  status_icon="?"
  case "${STEP_STATUS[$i]}" in
    d|D) status_icon="✓" ;;
    s|S) status_icon="↷" ;;
    b|B) status_icon="✗" ;;
  esac
  if [[ -n "${STEP_NOTES[$i]}" ]]; then
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]} — ${STEP_NOTES[$i]}"
  else
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]}"
  fi
done
ms_buffer_append ""
if [[ ${#FAIL_CHECK[@]} -gt 0 ]]; then
  ms_buffer_append "## 失败模式自检"
  ms_buffer_append ""
  for line in "${FAIL_CHECK[@]}"; do
    ms_buffer_append "- $line"
  done
  ms_buffer_append ""
fi

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "workflow" "${WORKFLOW}" \
    "step_count" "${#SOP_STEPS[@]}" \
    "failure_check_count" "${#FAILURE_MODES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "product-tabletop-walkthrough"
fi
